from itertools import combinations


class Solution:
    def maximumWeight(self, intervals):
        n = len(intervals)
        best_score = -1
        best_idx = None
        for size in range(0, 5):
            for combo in combinations(range(n), size):
                order = sorted(combo, key=lambda i: intervals[i][0])
                ok = True
                for a, b in zip(order, order[1:]):
                    if intervals[a][1] >= intervals[b][0]:
                        ok = False
                        break
                if not ok:
                    continue
                score = sum(intervals[i][2] for i in combo)
                idx_sorted = tuple(sorted(combo))
                if score > best_score or (score == best_score and (best_idx is None or idx_sorted < best_idx)):
                    best_score = score
                    best_idx = idx_sorted
        return list(best_idx) if best_idx is not None else []

