var maximumWeight = function(intervals) {
    const n = intervals.length;
    const order = Array.from({ length: n }, (_, i) => i).sort((a, b) => intervals[a][1] - intervals[b][1]);
    const L = order.map(i => intervals[i][0]);
    const R = order.map(i => intervals[i][1]);
    const W = order.map(i => intervals[i][2]);

    function lowerBound(arr, target) {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < target) lo = mid + 1; else hi = mid;
        }
        return lo;
    }
    function cmpIdx(a, b) {
        const n2 = Math.min(a.length, b.length);
        for (let i = 0; i < n2; i++) if (a[i] !== b[i]) return a[i] - b[i];
        return a.length - b.length;
    }

    const dp = [];
    for (let i = 0; i <= n; i++) {
        dp.push(new Array(5).fill(null).map(() => [0, []]));
    }
    for (let i = 1; i <= n; i++) {
        const pIdx = lowerBound(R, L[i - 1]);
        for (let k = 0; k < 5; k++) {
            let best = dp[i - 1][k];
            if (k >= 1) {
                const [baseScore, baseIdx] = dp[pIdx][k - 1];
                const newScore = baseScore + W[i - 1];
                const newIdx = baseIdx.concat([order[i - 1]]).sort((a, b) => a - b);
                if (newScore > best[0] || (newScore === best[0] && cmpIdx(newIdx, best[1]) < 0)) {
                    best = [newScore, newIdx];
                }
            }
            dp[i][k] = best;
        }
    }
    return dp[n][4][1];
};
